// Initial template generated by Claude, with wiring up, edits, and function edits done manually with AI guidance
<template>
  <div class="container py-4" style="max-width:640px;">

    <div class="p-3 mb-3 rounded"
         style="background:#e8f4e6;border:1px solid #5a9e56;">
      <h4 style="color:#5a9e56;" class="mb-0">Your Profile</h4>
      <small class="text-secondary">Your account details</small>
    </div>

    <div class="card border p-4">

      <div class="d-flex align-items-center gap-3 mb-4">
        <div class="avatar-circle" style="width:72px;height:72px;font-size:1.5rem;">
          {{ initials }}
        </div>
        <div>
          <div class="fw-bold" style="font-size:1.2rem;color:#5a9e56;">{{ displayName }}</div>
          <div class="text-muted small">{{ roleLabel }}</div>
        </div>
      </div>

      <div class="mb-3">
        <label class="form-label small fw-semibold">Display Name</label>
        <input type="text" class="form-control form-control-sm" :value="displayName" disabled>
        <small class="text-muted" style="font-size:0.7rem;">
          Derived from your email address.
        </small>
      </div>

      <div class="mb-3">
        <label class="form-label small fw-semibold">Email Address</label>
        <input type="email" class="form-control form-control-sm" :value="email" disabled>
      </div>

      <div class="mb-3">
        <label class="form-label small fw-semibold">User ID</label>
        <div class="d-flex gap-2">
          <input type="text" class="form-control form-control-sm" :value="userId ?? ''" disabled>
          <button class="btn btn-gf btn-sm" @click="copyId" :disabled="userId == null">
            {{ copied ? 'Copied' : 'Copy' }}
          </button>
        </div>
        <small class="text-muted" style="font-size:0.7rem;">
          Share this number with your nutritionist so they can invite you as a client.
        </small>
      </div>

      <div class="mb-3">
        <label class="form-label small fw-semibold">Account Type</label>
        <input type="text" class="form-control form-control-sm" :value="roleLabel" disabled>
      </div>

      <hr class="my-4">

      <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary btn-sm" @click="goBack">Back</button>
        <button class="btn btn-sm"
                style="background:#fde8e8;border:1px solid #d99;color:#c44;"
                @click="handleLogout">
          Log Out
        </button>
      </div>
    </div>

  </div>
</template>

<script setup>
import { computed, ref } from 'vue'
import { useRouter } from 'vue-router'
import { currentUser, logout } from '../auth.js'

const router = useRouter()

const displayName = computed(() => currentUser.value.name || '—')
const email = computed(() => currentUser.value.email || '—')
const userId = computed(() => currentUser.value.userId)

const roleLabel = computed(() => {
  const r = currentUser.value.role
  if (r === 'professional') return 'Nutrition Professional'
  if (r === 'subscriber') return 'Subscriber'
  return 'Standard User'
})

const initials = computed(() => {
  const parts = (currentUser.value.name || '').trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) return '?'
  return parts.slice(0, 2).map(p => p[0].toUpperCase()).join('')
})

const copied = ref(false)
async function copyId() {
  if (userId.value == null) return
  try {
    await navigator.clipboard.writeText(String(userId.value))
    copied.value = true
    setTimeout(() => { copied.value = false }, 1500)
  } catch {
    // navigator.clipboard isn't available on http or older browsers — just no-op
  }
}

async function handleLogout() {
  await logout()
  router.push('/')
}

function goBack() {
  router.push('/dashboard')
}
</script>
